package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.cardviewer.ViewerCommand
import org.junit.Test
import org.junit.runner.RunWith
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.*

@RunWith(AndroidJUnit4::class)
class RescheduleCommandTest : RobolectricTest() {

    @Test
    fun testRescheduleCommandExists() {
        // Verify that RESCHEDULE command is available in ViewerCommand
        val commands = ViewerCommand.values()
        val rescheduleCommand = commands.firstOrNull { it == ViewerCommand.RESCHEDULE }

        assertThat("RESCHEDULE command should exist", rescheduleCommand, notNullValue())
    }

    @Test
    fun testRescheduleCommandHasCorrectResourceId() {
        // Verify that RESCHEDULE command uses the correct string resource
        val rescheduleCommand = ViewerCommand.RESCHEDULE

        assertThat(
            "RESCHEDULE command should use card_editor_reschedule_card resource",
            rescheduleCommand.resourceId,
            equalTo(R.string.card_editor_reschedule_card)
        )
    }

    @Test
    fun testRescheduleCommandPreferenceKey() {
        // Verify that RESCHEDULE command has the correct preference key
        val rescheduleCommand = ViewerCommand.RESCHEDULE

        assertThat(
            "RESCHEDULE command should have preference key 'binding_RESCHEDULE'",
            rescheduleCommand.preferenceKey,
            equalTo("binding_RESCHEDULE")
        )
    }
}
"}

